module mux2_to_1(in1, in2 , invalid_out, sel);
input [4:0] in1, in2;
input sel;
output [4:0] invalid_out;
reg [4:0] invalid_out;
always@(sel or in1 or in2)
begin
    case(sel)
        0   : invalid_out = in1;
        1   : invalid_out = in2;
        default: invalid_out = in1;
    endcase
end
endmodule
